        {
            var parms = string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
            Console.WriteLine($"  - {type.Name}({parms})");
        }
    }

    // Methods/Interface members
    var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
        .Where(m => !m.IsSpecialName).ToArray();
    if (methods.Length > 0)
    {
        Console.WriteLine($"Methods: {methods.Length}");
        foreach (var method in methods.Take(3))
        {
            var parms = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
            Console.WriteLine($"  - {method.ReturnType.Name} {method.Name}({parms})");
        }
    }

    // Properties
    var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance);
    if (props.Length > 0)
    {
        Console.WriteLine($"Properties: {props.Length}");
        foreach (var prop in props.Take(5))
        {
            var access = $"{{get;{(prop.CanWrite ? "set;" : "")}}}";
            Console.WriteLine($"  - {prop.PropertyType.Name} {prop.Name} {access}");
        }
    }
}
