## **Example: Complete Agentic Workflow**

```csharp
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// 1. Create an IChatClient (e.g., OpenAI)
var openaiClient = new OpenAIClient("your-api-key");
var chatClient = openaiClient.AsChatClient("gpt-4o");

// 2. Create tools
var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        (string location) => $"Weather in {location}: 72°F, Sunny",
        "get_weather",
        "Get the weather for a location"
    ),
    AIFunctionFactory.Create(
        (string query) => $"Search results for: {query}",
        "search_web",
        "Search the web"
    )
};

// 3. Create the agent
var agentOptions = new ChatClientAgentOptions
{
    Id = "weather_assistant",
    Name = "Weather Assistant",
    Description = "Helps with weather and web searches",
    ChatOptions = new ChatOptions
    {
        Temperature = 0.7,
        MaxOutputTokens = 1000,
    }
};

var agent = new ChatClientAgent(
    chatClient,
    instructions: "You are a helpful weather assistant. Use available tools to help users.",
    options: agentOptions,
    loggerFactory: null,
    services: null
);

// 4. Create a conversation session
var session = await agent.CreateSessionAsync(
    conversationId: Guid.NewGuid().ToString(),
    CancellationToken.None
);

// 5. Invoke the agent
var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Tools = tools,
        ToolMode = AutoChatToolMode.Default,
    }
};

var response = await agent.RunAsync(
    message: "What's the weather like in Seattle?",
    session,
    runOptions,
    CancellationToken.None
);

Console.WriteLine($"Agent: {response.Output}");

// 6. Continue conversation
var response2 = await agent.RunAsync(
    message: "How about San Francisco?",
    session,
    runOptions,
    CancellationToken.None
);

Console.WriteLine($"Agent: {response2.Output}");
```

