    Console.ResetColor();

    try
    {
        var session = await agent.CreateSessionAsync(cancellationToken: CancellationToken.None);

        var runOptions = new ChatClientAgentRunOptions
        {
            ChatOptions = new ChatOptions
            {
                Temperature = 0f,
                MaxOutputTokens = 4096,
                Tools = tools,
