/// <summary>Simulated web search that uses the OpenAI-compatible chat client for demo purposes.</summary>
static class WebSearch
{
    private static readonly HttpClient s_httpClient = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
    };

    /// <summary>
    /// Performs a web search using a free search API and returns result snippets.
    /// Falls back to a description when no API is available.
    /// </summary>
    public static async Task<string> SearchAsync(string query)
    {
        // Try DuckDuckGo Instant Answer API (no key required)
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var json = await s_httpClient.GetStringAsync(url);
            var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new StringBuilder();

            // Abstract / main answer
            var abstractText = root.GetProperty("AbstractText").GetString();
            var abstractSource = root.GetProperty("AbstractSource").GetString();
            var abstractUrl = root.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.AppendLine($"**{abstractSource}**: {abstractText}");
                results.AppendLine($"  URL: {abstractUrl}");
                results.AppendLine();
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var related))
            {
                var count = 0;
                foreach (var item in related.EnumerateArray())
                {
                    if (count >= 5) break;
                    var text = item.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    var firstUrl = item.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                    {
                        results.AppendLine($"- {text}");
                        if (!string.IsNullOrWhiteSpace(firstUrl))
                            results.AppendLine($"  URL: {firstUrl}");
                        count++;
                    }
                }
            }

            if (results.Length > 0)
                return results.ToString();

            return $"No detailed results found for \"{query}\". Try refining the query.";
        }
        catch
        {
            return $"Web search unavailable. Query was: \"{query}\". Please reason from your training knowledge.";
        }
    }
}

/// <summary>Simple in-memory notebook for the agent to store research findings.</summary>
sealed class Notebook
{
    private readonly List<Note> _notes = [];

    public void Add(string title, string content) =>
        _notes.Add(new Note(title, content, DateTime.UtcNow));

    public IReadOnlyList<Note> GetAll() => _notes.AsReadOnly();

    public void Clear() => _notes.Clear();

    public record Note(string Title, string Content, DateTime SavedAt);
}

